def find_all(text, pattern):
    n = len(text)
    m = len(pattern)
    if m == 0:
        return list(range(n + 1))
    if m > n:
        return []
    # Boyer-Moore-Horspool: build bad character table
    bad_char = {}
    for i in range(m - 1):
        bad_char[pattern[i]] = m - 1 - i
    result = []
    i = 0
    while i <= n - m:
        j = m - 1
        while j >= 0 and text[i + j] == pattern[j]:
            j -= 1
        if j < 0:
            result.append(i)
            i += 1
        else:
            shift = bad_char.get(text[i + m - 1], m)
            i += max(1, shift)
    return result

